import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    def distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    best_node = None
    min_distance = float('inf')

    for idx, customer in enumerate(unvisited_customers):
        current_distance = distance(cur_truck_pos, customer)

        # Check if any other truck is closer or the same distance to this customer
        is_any_truck_closer = any(
            distance(truck_pos, customer) <= current_distance
            for truck_pos in all_truck_pos if not np.array_equal(truck_pos, cur_truck_pos)
        )

        # Choose this customer if no other truck is closer to it
        if not is_any_truck_closer and current_distance < min_distance:
            min_distance = current_distance
            best_node = idx

    # If no best node found, return None to wait for more optimal choices
    if best_node is None:
        return None

    return best_node

